import { Component, OnInit } from '@angular/core';

// تعريف واجهة (Interface) لبيانات الخدمات لضمان تنظيم الكود
interface MedicalService {
  title: string;
  img: string;
}

// تعريف واجهة (Interface) لبيانات الأطباء
interface Doctor {
  name: string;
  specialty: string;
  avatar: string;
}

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit {

  // مصفوفة الخدمات (Our Services)
  services: MedicalService[] = [
    { title: 'PEDIATRICIAN', img: 'assets/service1.png' },
    { title: 'ULTRASOUND', img: 'assets/service2.png' },
    { title: 'DIAGNOSTICS', img: 'assets/service3.png' }
  ];

  // مصفوفة الأطباء (Our Doctors)
  doctors: Doctor[] = [
    { name: 'Dr. Albert Flores', specialty: 'Pediatrician', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Dianne Russell', specialty: 'Diagnostics', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Esther Howard', specialty: 'Ultrasound', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Cody Fisher', specialty: 'Pediatrician', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Theresa Webb', specialty: 'Cardiologist', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Savannah Nguyen', specialty: 'Pediatrician', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Leslie Alexander', specialty: 'Diagnostics', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Floyd Miles', specialty: 'Ultrasound', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Ronald Richards', specialty: 'Pediatrician', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Marvin McKinney', specialty: 'Cardiologist', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Jerome Bell', specialty: 'Pediatrician', avatar: 'assets/doctor-avatar.png' },
    { name: 'Dr. Kristin Watson', specialty: 'Diagnostics', avatar: 'assets/doctor-avatar.png' }
  ];

  constructor() { }

  ngOnInit(): void {
    // يمكنكِ هنا جلب البيانات من API مستقبلاً إذا لزم الأمر
  }

  // دالة تُنفذ عند إرسال الفورم (Form Submission)
  onSubmitMessage(event: Event): void {
    event.preventDefault();
    console.log('Message sent successfully!');
    // هنا يمكنكِ ربط الفورم مع Backend أو إظهار رسالة نجاح للمستخدم
  }
}
